<span class="line"><span style="color:#CDD6F4;">                    output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#89B4FA;font-style:italic;">format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot; </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> change</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">value</span><span style="color:#9399B2;">()));</span></span>
